var e=JSON.parse(`[{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐야, 버터맨? 어울리지 않게 말도 없고.","JPN":"どうかしたの、バターマン？　無口だなんて、らしくないわよ。","ENG":"What's wrong, Sleazeball? You're strangely quiet.","TWN":"幹嘛啊，小白臉？一句話都不說，真不像你。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어제 만난 아가씨에게 차이기라도 했어?","JPN":"昨日会った娘に振られたとか？","ENG":"Did you get dumped by a lady you met last night?","TWN":"是被昨天遇見的小姐甩了喔？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 그런 정도로 힘이 빠져서야 제이크 실격이지.","JPN":"ハハ、俺がそれくらいで落ち込むわけないだろ。","ENG":"Hah hah. I'm Jake. Things like that don't let me down.","TWN":"哈哈，被甩了就垂頭喪氣的，沒資格當傑克·沃克吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"차였다는 건 새로운 사랑을 만날 기회라는 뜻 아니겠어?","JPN":"振られたということは、新しい恋を迎えるチャンスだしな？","ENG":"Besides, being dumped means that I have a new opportunity for love, right?","TWN":"被甩了不就意味著有了邂逅嶄新愛情的機會嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭔 헛소리야? 그럼 왜 그렇게 의욕 없는 표정을 하고 있는 건데?","JPN":"なに寝言言ってるの？\\nじゃあ、どうしてそんなにテンション低い顔をしてるわけ？","ENG":"Okay, then why do you look so unenthusiastic right now?","TWN":"說什麼鬼話啊？那你幹嘛一臉毫無幹勁的表情啊。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그냥...... 좀 지쳐서......","JPN":"なんとなく……ちょっと疲れちゃってな……","ENG":"I'm... I'm just tired.","TWN":"就這是……有些累了……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지치다니, 뭐가?","JPN":"疲れる？　どうして？","ENG":"Tired of what?","TWN":"你竟然會說累，有什麼好累的？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"말하자면 좀 긴데 말이지......","JPN":"話すと長くなるんだが……","ENG":"It's a long story.","TWN":"這說來話長……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"내가 용병을 싫어한다고 이야기 했었던가?","JPN":"俺、傭兵が嫌いって話、したかな？","ENG":"Did I tell you that I hate mercenaries?","TWN":"我有說過我討厭傭兵嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어라? 그랬나?","JPN":"あれ、そうだっけ？","ENG":"Huh? Do you?","TWN":"咦？有嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러고 보니...... 그랬던 거 같기도 하고.","JPN":"言われてみれば……そんなこと聞いた気もする。","ENG":"Now that I think of it, yes, I think you said that before.","TWN":"這麼說來……好像真有這麼一回事。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"우리 집안은 원래 군인 집안이었거든.","JPN":"うちは代々軍人一家でな。","ENG":"I'm from a military family.","TWN":"我家以前是軍人家庭。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"할아버지만 해도 아주 전통적이고 고지식한 노병이었으니까.","JPN":"祖父はとても伝統的で生真面目なタイプの老兵だった。","ENG":"Everyone, including my grandpa, were traditional soldiers.","TWN":"雖然只有祖父是軍人，但他是非常傳統，而且固執的老兵。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 관리실패가 벌어지고 대정화 전쟁이 벌어지면서......","JPN":"だが、管理失敗で大浄化戦争が勃発して……","ENG":"But when the Administration Failure happened, followed by the Grand Purification War,","TWN":"但發生管理失敗後，隨著淨化之戰的爆發……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아버지는 군인이 아니라 용병이 되길 선택했어.","JPN":"父は軍人ではなく傭兵の道を選んだ。","ENG":"my dad chose to be a mercenary instead of a soldier.","TWN":"我父親沒有成為軍人，而是選擇成為了一個傭兵。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"알겠지만 그때는 전통적인 군인상 같은 게 통하던 시절이 아니었거든.","JPN":"知ってるだろうが、当時は伝統的な軍人像が通じるような時代じゃなかったんだ。","ENG":"As you know, traditional military virtues meant nothing at that time.","TWN":"我想妳也知道，在那個時代，傳統的軍人勳章並不是很吃香。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};